            // and uses STAC/CLAC for SMAP-safe access.
            let r = unsafe {
                crate::mm::user::copy_to_user(
                    (&raw const v).cast::<u8>(),
                    user_buf,
                    core::mem::size_of::<i32>(),
                )
            };
            if let Err(e) = r {
                return linux_err(linux_errno_for(e));
            }
            SyscallResult::ok(0)
