        let itv_zero = [0u8; ITIMERVAL_SIZE];
        let itv_zero_ptr = itv_zero.as_ptr() as u64;
        let a = SyscallArgs { arg0: 99, arg1: itv_zero_ptr, arg2: 0,
            arg3: 0, arg4: 0, arg5: 0 };
