        let a = SyscallArgs { arg0: 0, arg1: 0, arg2: 0, arg3: 0,
            arg4: 0, arg5: 0 };
        if dispatch_linux(nr::PAUSE, &a).value
            != -i64::from(errno::ENOSYS) {
            serial_println!("[syscall/linux]   FAIL: pause not ENOSYS");
            return Err(KernelError::InternalError);
        }
