        let a = SyscallArgs { arg0: 0, arg1: 0, arg2: 0, arg3: 0,
            arg4: 0, arg5: 0 };
        if dispatch_linux(nr::ACCESS, &a).value
            != -i64::from(errno::EFAULT) {
            serial_println!(
                "[syscall/linux]   FAIL: access(NULL,0) not EFAULT"
            );
            return Err(KernelError::InternalError);
        }
